type ButtonProps =
  | ({ variant: 'primary'; onClick: () => void } & React.ComponentPropsWithoutRef<'button'>)
  | ({ variant: 'link'; href: string } & React.ComponentPropsWithoutRef<'a'>);

function Button(props: ButtonProps) {
  if (props.variant === 'link') {
    const { variant, href, ...rest } = props;
    return <a href={href} {...rest} />;
  }
  const { variant, onClick, ...rest } = props;
  return <button onClick={onClick} {...rest} />;
}

