export function FadeInCard({ children }: { children: React.ReactNode }) {
  const reduce = useReducedMotion();

  return (
    <motion.div
      initial="hidden"
      animate="visible"
      variants={reduce ? {} : variants}
      transition={{ duration: 0.25, ease: 'easeOut' }}
    >
      {children}
    </motion.div>
  );
}

// useConfirm hook backed by ModalContext
function useConfirm() {
  const { openModal, closeModal } = useModalContext();

  return (message: string): Promise<boolean> =>
    new Promise((resolve) => {
      openModal(
        <ConfirmDialog
          message={message}
          onConfirm={() => { resolve(true); closeModal(); }}
          onCancel={() => { resolve(false); closeModal(); }}
        />
      );
    });
}

